import React from 'react';
import { BrowserRouter as Router, Switch, Route } from 'react-router-dom';
import Dashboard from './components/Dashboard';
import ItemManagement from './components/ItemManagement';
import CategoryManagement from './components/CategoryManagement';
import PurchaseManagement from './components/PurchaseManagement';
import SaleManagement from './components/SaleManagement';
import BillManagement from './components/BillManagement';
import CompanyManagement from './components/CompanyManagement';
import ExpenseManagement from './components/ExpenseManagement';
import FocManagement from './components/FocManagement';
import ReportManagement from './components/ReportManagement';

function App() {
  return (
    <Router>
      <Switch>
        <Route path="/" exact component={Dashboard} />
        <Route path="/items" component={ItemManagement} />
        <Route path="/categories" component={CategoryManagement} />
        <Route path="/purchases" component={PurchaseManagement} />
        <Route path="/sales" component={SaleManagement} />
        <Route path="/bills" component={BillManagement} />
        <Route path="/companies" component={CompanyManagement} />
        <Route path="/expenses" component={ExpenseManagement} />
        <Route path="/focs" component={FocManagement} />
        <Route path="/reports" component={ReportManagement} />
      </Switch>
    </Router>
  );
}

export default App;
